mapper.select:
SELECT database_id, COALESCE(schema_name || '.' || table_name, 'unknown') as table_name, session_phase, session_progress, autovacuum, elapsed_seconds, heap_blks_total, heap_blks_scanned, heap_blks_vacuumed, n_dead_tup FROM vacuum_raw_metrics WHERE database_id = #{databaseId} AND collected_at >= NOW() - INTERVAL '5 minutes' AND elapsed_seconds IS NOT NULL
AND table_name = #{tableName}
ORDER BY elapsed_seconds DESC LIMIT 50
